const s = context.panel.data.series[0];
let v = 0;
if (s) {
  const f = s.fields.find((f) => f.type === 'number');
  if (f) {
    const a = f.values.toArray ? f.values.toArray() : f.values;
    for (let i = a.length - 1; i >= 0; i--) { if (a[i] != null) { v = a[i]; break; } }
  }
}
const color = v >= 92 ? '#e66767' : v >= 80 ? '#c98500' : '#3987e5';
return {
  series: [{
    type: 'gauge', startAngle: 220, endAngle: -40, min: 0, max: 100,
    radius: '88%', center: ['50%', '60%'],
    progress: { show: true, width: 10, roundCap: true, itemStyle: { color } },
    axisLine: { roundCap: true, lineStyle: { width: 10, color: [[1, 'rgba(128,128,128,.14)']] } },
    axisTick: { show: false }, splitLine: { show: false }, axisLabel: { show: false },
    pointer: { show: false }, anchor: { show: false }, title: { show: false },
    detail: { valueAnimation: true, fontSize: 19, fontWeight: 600,
              offsetCenter: [0, '-8%'], formatter: (x) => Math.round(x) + '%', color },
    data: [{ value: v }]
  }]
};

